import numpy as np

def q_learning(n_states: int, n_episodes: int, alpha: float, gamma: float, epsilon: float) -> np.ndarray:
    Q = np.zeros((n_states, 2))
    goal = n_states - 1

    for _ in range(n_episodes):
        s = 0
        while s != goal:
            if np.random.random() < epsilon:
                a = np.random.randint(2)
            else:
                a = np.argmax(Q[s])

            s_next = int(np.clip(s + (1 if a == 1 else -1), 0, goal))
            r = 1.0 if s_next == goal else 0.0

            Q[s, a] += alpha * (r + gamma * np.max(Q[s_next]) - Q[s, a])
            s = s_next

    return Q
